import numpy as npimport jsonfrom astropy.io import fitsfrom dataclasses import dataclassfrom criresviz.skycalc import compute_sky@dataclass(slots=True)class Sky:    """    Atmospheric transmission and radiance model computed with SkyCalc.    A Sky object stores the wavelength grid together with the atmospheric    transmission, sky radiance, and the SkyCalc parameters used to generate    the model.    Instances can be created either from an existing SkyCalc FITS file or    directly from SkyCalc using :meth:`from_skycalc`.    Parameters    ----------    wavelength : ndarray        Wavelength array in μm.    transmission : ndarray        Total atmospheric transmission.    radiance : ndarray        Total sky radiance in        photons s⁻¹ m⁻² μm⁻¹ arcsec⁻².    parameters : dict        Dictionary containing the SkyCalc input parameters.    """    wavelength: np.ndarray    transmission: np.ndarray    radiance: np.ndarray    parameters: dict        # properties        @property    def wavelength_range(self):        """Minimum and maximum wavelength."""        return (            self.wavelength.min(),            self.wavelength.max(),        )    @property    def transmission_range(self):        """Minimum and maximum atmospheric transmission."""        return (            self.transmission.min(),            self.transmission.max(),        )    @property    def radiance_range(self):        """Minimum and maximum sky radiance."""        return (            self.radiance.min(),            self.radiance.max(),        )#    @property#    def mean_transmission(self):#        """Mean atmospheric transmission."""#        return self.transmission.mean()    @property    def available_parameters(self):        """Return all available SkyCalc parameters."""        return sorted(self.parameters.keys())            # constructors        @classmethod    def from_file(cls, filename):        """        Create a Sky object from a SkyCalc FITS file.                Parameters        ----------        filename : str or Path            Path to the SkyCalc FITS file.                Returns        -------        Sky            Sky object containing the transmission, radiance,            wavelength grid and SkyCalc parameters.        """        with fits.open(filename) as hdul:            table = hdul[1].data            header = hdul[0].header            wavelength = table["lam"]/1000            transmission = (                table["trans_ma"]                * table["trans_o3"]                * table["trans_rs"]                * table["trans_ms"]            )            radiance = (                table["flux_sml"]                + table["flux_ssl"]                + table["flux_zl"]                + table["flux_tie"]                + table["flux_tme"]                + table["flux_ael"]                + table["flux_arc"]            )                        comments = "\n".join(header["COMMENT"])                        start = comments.find("{")            end = comments.rfind("}") + 1                        parameters = json.loads(                comments[start:end]            )        return cls(            wavelength=wavelength,            transmission=transmission,            radiance=radiance,            parameters=parameters,        )        ##############################################    @classmethod    def from_skycalc(cls, **kwargs):        """        Compute a SkyCalc model and return it as a Sky object.            Parameters        ----------        **kwargs            Keyword arguments passed directly to            :func:`criresviz.skycalc.compute_sky`.            Returns        -------        Sky            Newly computed sky model.        """        filename = compute_sky(**kwargs)        return cls.from_file(filename)            # public methods        def get_parameter(self, *names):        """        Return one or more SkyCalc parameters.            Parameters        ----------        *names : str            Parameter names.            Returns        -------        object or dict            A single parameter value if one name is given,            otherwise a dictionary mapping parameter names to values.        """            if len(names) == 1:            return {names: self.parameters[names[0]]}            return {name: self.parameters[name] for name in names}        ##############################################        def mean_transmission(self, wavelength_range=None):        """        Return the mean atmospheric transmission.        """        return self.transmission[            self._mask(wavelength_range)        ].mean()        ##############################################        def mean_radiance(self, wavelength_range=None):        """        Return the mean sky radiance.        """        return self.radiance[            self._mask(wavelength_range)        ].mean()        ##############################################        def _mask(self, wavelength_range):        """        Return a boolean mask selecting a wavelength interval.        """            if wavelength_range is None:            return slice(None)            wmin, wmax = wavelength_range            return (            (self.wavelength >= wmin)            &            (self.wavelength <= wmax)        )        ##############################################        def plot(self, ax=None):        """        Plot the sky transmission or radiance.            Parameters        ----------        ax : matplotlib.axes.Axes, optional            Axis to draw on.            Returns        -------        matplotlib.axes.Axes            Axis containing the plot.        """        from criresviz.plotting.sky import _draw_sky        return _draw_sky(self, ax)        # dunder methods        def __str__(self):        wmin, wmax = self.wavelength_range        return (            "Sky\n"            "──────────────────────────────\n"            f"Airmass:          {self.parameters['airmass']:.2f}\n"            f"Wavelength:       {wmin:.2f}–{wmax:.2f} nm\n"            f"Wavelength resolution: {self.parameters['wres']}\n"            f"Precipitable water vapour: {self.parameters['pwv']:.2f}\n"            f"Observatory: {self.parameters['observatory']}\n"            f"Molecular Emission of Upper Atmosphere: {self.parameters['incl_upperatm']}\n"            f"Molecular Emission of Lower Atmosphere: {self.parameters['incl_loweratm']}\n"        )        